CREATE TABLE Nums ( n INT, PRIMARY KEY(n))
    SELECT a.n*1000 + b.n*100 + c.n*10 + d.n
        FROM Num10 AS a
        JOIN Num10 AS b  -- note "cross join"
        JOIN Num10 AS c
        JOIN Num10 AS d;

SELECT 123 + n FROM Nums WHERE n < 234-123+1;

SELECT 12345 + 15*n FROM Nums WHERE n < (23456-12345+1)/15;

